solution_code:
#include <iostream>
#include <iomanip>
#include <memory>
#include <string>
#include <vector>

class Shape
{
public:
    virtual double area() const = 0;
    virtual ~Shape() = default;
};

class Circle : public Shape
{
    double m_radius{};
public:
    Circle(double radius) : m_radius{radius} {}
    double area() const override { return 3.14159265 * m_radius * m_radius; }
};

class Rectangle : public Shape
{
    double m_width{};
    double m_height{};
public:
    Rectangle(double w, double h) : m_width{w}, m_height{h} {}
    double area() const override { return m_width * m_height; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<Shape>> shapes{};
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "circle")
        {
            double r{};
            std::cin >> r;
            shapes.push_back(std::make_unique<Circle>(r));
        }
        else
        {
            double w{}, h{};
            std::cin >> w >> h;
            shapes.push_back(std::make_unique<Rectangle>(w, h));
        }
    }

    std::cout << std::fixed << std::setprecision(2);
    double total{0.0};
    for (const auto& s : shapes)
    {
        double a{s->area()};
        total += a;
        std::cout << "Area: " << a << '\n';
    }
    std::cout << "Total: " << total << '\n';
    return 0;
}

