#include <iostream>
#include <iomanip>
#include <memory>
#include <string>
#include <vector>

class BillingItem
{
public:
    virtual double cost() const = 0;
    virtual ~BillingItem() = default;
};

class Flat : public BillingItem
{
    double m_price{};
public:
    Flat(double price) : m_price{price} {}
    double cost() const override { return m_price; }
};

class Hourly : public BillingItem
{
    double m_rate{};
    double m_hours{};
public:
    Hourly(double rate, double hours) : m_rate{rate}, m_hours{hours} {}
    double cost() const override { return m_rate * m_hours; }
};

class Subscription : public BillingItem
{
    double m_monthly{};
    double m_months{};
public:
    Subscription(double monthly, double months) : m_monthly{monthly}, m_months{months} {}
    double cost() const override { return m_monthly * m_months; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<BillingItem>> items{};
    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "flat")
        {
            double p{};
            std::cin >> p;
            items.push_back(std::make_unique<Flat>(p));
        }
        else if (type == "hourly")
        {
            double r{}, h{};
            std::cin >> r >> h;
            items.push_back(std::make_unique<Hourly>(r, h));
        }
        else
        {
            double m{}, mo{};
            std::cin >> m >> mo;
            items.push_back(std::make_unique<Subscription>(m, mo));
        }
    }

    std::cout << std::fixed << std::setprecision(2);
    double total{0.0};
    for (int i{0}; i < n; ++i)
    {
        double c{items[i]->cost()};
        total += c;
        std::cout << "Item " << (i + 1) << ": $" << c << '\n';
    }
    std::cout << "Total: $" << total << '\n';
    return 0;
}
